from sentence_transformers import SentenceTransformer, util

model = SentenceTransformer("all-MiniLM-L6-v2")

def find_duplicates(texts, threshold=0.8):
    embs = model.encode(texts, normalize_embeddings=True, convert_to_tensor=True)
    sim = util.cos_sim(embs, embs)
    dupes = []
    for i in range(len(texts)):
        for j in range(i + 1, len(texts)):
            if sim[i][j] >= threshold:
                dupes.append((texts[i], texts[j], float(sim[i][j])))
    return dupes

tickets = [
    "I can't access my account",
    "Unable to log into my account",
    "How do I upgrade my plan?",
]

dupes = find_duplicates(tickets, threshold=0.75)
for a, b, score in dupes:
    print(f"{score:.3f} | '{a}' â‰ˆ '{b}'")

