class FAQMatcher:
    def __init__(self, faq: dict, threshold: float = 0.3):
        # faq is {question: answer, ...}
        self.faq = faq
        self.threshold = threshold
        self.questions = list(faq.keys())
        self.answers = list(faq.values())
        self.vectors = [self._encode(q) for q in self.questions]

    def _encode(self, text: str) -> dict:
        words = text.lower().split()
        vec = {}
        for w in words:
            vec[w] = vec.get(w, 0) + 1
        return vec

    def _cosine_sim(self, a: dict, b: dict) -> float:
        shared = set(a) & set(b)
        dot = sum(a[w] * b[w] for w in shared)
